class Solution:
    def minCost(self, nums):
        def rec(arr):
            if len(arr) < 3:
                return max(arr) if arr else 0
            a, b, c = arr[0], arr[1], arr[2]
            rest = arr[3:]
            return min(
                max(a, b) + rec([c] + rest),
                max(a, c) + rec([b] + rest),
                max(b, c) + rec([a] + rest),
            )
        return rec(list(nums))

