var minCost = function(nums) {
    const n = nums.length;
    const memo = new Map();
    function solve(i, j) {
        const key = i * (n + 1) + (j + 1);
        if (memo.has(key)) return memo.get(key);
        const held = j < 0 ? null : nums[j];
        const total = (held === null ? 0 : 1) + (n - i);
        let result;
        if (total < 3) {
            const vals = held === null ? nums.slice(i) : [held, ...nums.slice(i)];
            result = vals.length ? Math.max(...vals) : 0;
        } else if (held === null) {
            const a = nums[i], b = nums[i + 1], c = nums[i + 2];
            result = Math.min(
                Math.max(a, b) + solve(i + 3, i + 2),
                Math.max(a, c) + solve(i + 3, i + 1),
                Math.max(b, c) + solve(i + 3, i)
            );
        } else {
            const a = nums[i], b = nums[i + 1];
            result = Math.min(
                Math.max(held, a) + solve(i + 2, i + 1),
                Math.max(held, b) + solve(i + 2, i),
                Math.max(a, b) + solve(i + 2, j)
            );
        }
        memo.set(key, result);
        return result;
    }
    return solve(0, -1);
};
